import vex

from google_adk import Agent, Workflow

vex_client = vex.Client(api_key="your-vex-api-key")

@vex_client.guard("legal-privilege-check")
def before_agent_callback(agent_input):
    # Check for PII and privileged patterns
    result = vex_client.check("privilege", {
        "text": agent_input["prompt"],
        "context": "legal"
    })
    if result["blocked"]:
        raise ValueError("Privilege violation detected")
    return agent_input

workflow = Workflow(agents=[research_agent, draft_agent], before_agent_callback=before_agent_callback)

@vex_client.guard("case-citation-validator")
def validate_citations_before_agent(input_data):
    citations = extract_citations(input_data["prompt"])
    for citation in citations:
        result = vex_client.check("legal-citation", {
            "citation": citation,
            "verify": True
        })
        if not result["valid"]:
            raise ValueError(f"Invalid citation: {citation}")
    return input_data

research_agent = Agent(
    model="gemini-2.0",
    before_callback=validate_citations_before_agent
)

@vex_client.guard("multi-agent-safety")
def monitor_agent_delegation(session_state, target_agent):
    # Track delegation graph
    vex_client.log("delegation", {
        "from": session_state["current_agent"],
        "to": target_agent.name,
        "session_id": session_state["id"]
    })

    # Check for cycles
    if vex_client.has_cycle(session_state["delegation_graph"]):
        raise ValueError("Circular dependency detected")

    # Validate tool format consistency
    if not tool_format_matches(target_agent.tools, session_state["expected_formats"]):
        raise ValueError("Tool format mismatch")

    return session_state

workflow.add_monitor(monitor_agent_delegation)
